const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

const getNearestHostile = (bot, radius) => {
  const hostiles = Object.values(bot.entities)
    .filter(e => {
      if (e.type !== 'mob') return false;
      const name = e.name.toLowerCase();
      return (name.includes('zombie') || name.includes('skeleton') || name.includes('spider') || name.includes('creeper') || name.includes('husk') || name.includes('drowned')) && e.health > 0;
    })
    .map(e => ({ entity: e, distance: bot.entity.position.distanceTo(e.position) }))
    .filter(e => e.distance <= radius)
    .sort((a, b) => a.distance - b.distance);
  return hostiles.length > 0 ? hostiles[0] : null;
};

const equipBestWeapon = async (bot, distance) => {
  const items = bot.inventory.items();
  const hasArrows = items.some(i => i.name === 'arrow');
  const bow = items.find(i => i.name === 'bow');
  const sword = items.find(i => i.name.includes('sword'));

  if (distance > 5 && bow && hasArrows) {
    await bot.equip(bow, 'hand');
    return 'bow';
  } else if (sword) {
    await bot.equip(sword, 'hand');
    return 'sword';
  }
  return 'none';
};

const equipArmor = async (bot) => {
  const armorTypes = ['helmet', 'chestplate', 'leggings', 'boots'];
  for (const type of armorTypes) {
    const armor = bot.inventory.items().find(i => i.name.includes(type));
    if (armor) {
        try { await bot.equip(armor, type === 'chestplate' ? 'torso' : (type === 'leggings' ? 'legs' : (type === 'helmet' ? 'head' : 'feet'))); } catch (e) {}
    }
  }
};

startBackgroundSkill(bot, 'defend_from_multiple_hosts', async function (token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);

  await equipArmor(bot);

  while (!token.cancelled && bot.health > 0 && Boolean(bot.entity)) {
    if (!bot.physicsEnabled) {
      await sleep(200);
      continue;
    }

    const targetInfo = getNearestHostile(bot, args.scanRadius);
    if (!targetInfo) {
      bot.pathfinder.setGoal(null);
      await sleep(500);
      continue;
    }

    const { entity, distance } = targetInfo;
    const weaponType = await equipBestWeapon(bot, distance);

    if (weaponType === 'sword' && distance < 4) {
      bot.lookAt(entity.position.offset(0, entity.height, 0));
      bot.attack(entity);
    } else if (weaponType === 'bow' && distance > 5) {
      bot.lookAt(entity.position.offset(0, entity.height, 0));
      bot.activateItem();
      await sleep(1200);
      bot.deactivateItem();
    }

    // Manage distance: If too close, move to preferredDistance.
    // If too far, move to within striking range or preferredDistance.
    if (distance < args.preferredDistance - 1 || distance > args.preferredDistance + 2) {
        const goal = new goals.GoalNear(entity.position.x, entity.position.y, entity.position.z, args.preferredDistance);
        bot.pathfinder.setGoal(goal);
    }

    // Check for healing if needed
    if (bot.health < 10 && bot.food > 10) {
        const food = bot.inventory.items().find(i => ['bread', 'cooked_beef', 'apple', 'carrot'].includes(i.name));
        if (food) {
            await bot.equip(food, 'hand');
            bot.activateItem();
            await sleep(1600);
            bot.deactivateItem();
        }
    }

    await sleep(200);
  }
  bot.pathfinder.setGoal(null);
});

return "<DEFENDING>: Priority set to nearest hostile within " + args.scanRadius + " blocks, maintaining " + args.preferredDistance + " block gap.";
